                            ks[key] = [key_time, key_time]
                        else:
                            ks[key] = [0, key_time]

            if not terminated_early and tc < best_cost:
                best_cost = tc
                best_pos = p

            # Advance prefix: process seq[p]
            if p < m:
                txn = txn_data[seq[p]]
                txn_len = txn[0][3]
                txn_start_p = 1
                for (op_type, key, pos, _) in txn:
                    if key in prefix_ks:
                        state = prefix_ks[key]
                        if op_type == 'w':
                            key_start = state[1] + 1
                        else:
                            key_start = state[0] + 1 if state[0] > 0 else 0
                        constraint = key_start - pos + 1
                        if constraint > txn_start_p:
                            txn_start_p = constraint
                txn_end_p = txn_start_p + txn_len - 1
                cost_p = txn_end_p - prefix_tc
                if cost_p < 0:
                    cost_p = 0
                prefix_tc += cost_p
                for (op_type, key, pos, _) in txn:
                    key_time = txn_start_p + pos - 1
                    if key in prefix_ks:
