import random

from txn_simulator import Workload
from workloads import WORKLOAD_1, WORKLOAD_2, WORKLOAD_3

# EVOLVE-BLOCK-START

import time
import math

def get_best_schedule(workload, num_seqs):
    """
    Prefix-sweep insertion with early termination + NEH + ILS with IG.

    Key innovation: find_best_insert uses incremental prefix computation
    and only evaluates the suffix for each position, with early termination
    when cost exceeds current best. This gives ~2-3x speedup over the naive
    approach of evaluating full sequences for each position.
    """
    n = workload.num_txns
    time_budget = 185
    start_time = time.time()

    def elapsed():
        return time.time() - start_time

    # Precompute transaction data for fast evaluation
    txn_data = []
    for i in range(n):
        ops = []
        for op in workload.txns[i]:
            ops.append((op[0], op[1], int(op[2]), int(op[3])))
        txn_data.append(ops)

    def fast_eval(seq):
        """Fast custom evaluator with per-key state tracking."""
        key_state = {}
        total_cost = 0
        for i in range(len(seq)):
            txn = txn_data[seq[i]]
            txn_len = txn[0][3]
            txn_start = 1
            for (op_type, key, pos, _) in txn:
                if key in key_state:
                    state = key_state[key]
                    if op_type == 'w':
                        key_start = state[1] + 1
                    else:
                        key_start = state[0] + 1 if state[0] > 0 else 0
                    constraint = key_start - pos + 1
                    if constraint > txn_start:
                        txn_start = constraint
            txn_end = txn_start + txn_len - 1
            cost = txn_end - total_cost
            if cost < 0:
                cost = 0
            total_cost += cost
            for (op_type, key, pos, _) in txn:
                key_time = txn_start + pos - 1
                if key in key_state:
                    state = key_state[key]
                    if op_type == 'w':
                        if key_time > state[0]:
                            state[0] = key_time
                    if key_time > state[1]:
                        state[1] = key_time
                else:
                    if op_type == 'w':
                        key_state[key] = [key_time, key_time]
                    else:
                        key_state[key] = [0, key_time]
        return total_cost

    def fast_eval_with_delays(seq):
        """Returns (total_cost, delays) where delays[i] = cost contribution at position i."""
        key_state = {}
        total_cost = 0
        delays = []
        for i in range(len(seq)):
            txn = txn_data[seq[i]]
            txn_len = txn[0][3]
            txn_start = 1
            for (op_type, key, pos, _) in txn:
                if key in key_state:
                    state = key_state[key]
                    if op_type == 'w':
                        key_start = state[1] + 1
                    else:
                        key_start = state[0] + 1 if state[0] > 0 else 0
                    constraint = key_start - pos + 1
                    if constraint > txn_start:
                        txn_start = constraint
            txn_end = txn_start + txn_len - 1
            cost = txn_end - total_cost
            if cost < 0:
                cost = 0
            total_cost += cost
            delays.append(cost)
            for (op_type, key, pos, _) in txn:
                key_time = txn_start + pos - 1
                if key in key_state:
                    state = key_state[key]
                    if op_type == 'w':
                        if key_time > state[0]:
                            state[0] = key_time
                    if key_time > state[1]:
                        state[1] = key_time
                else:
                    if op_type == 'w':
                        key_state[key] = [key_time, key_time]
                    else:
                        key_state[key] = [0, key_time]
        return total_cost, delays

    def fast_find_best_insert(seq, txn_idx, cost_bound=float('inf')):
        """
        Find best position to insert txn_idx using prefix sweep + early termination.

        Instead of evaluating n+1 full sequences from scratch, we:
        1. Maintain prefix state incrementally (advancing one txn at a time)
        2. For each position, copy prefix state and evaluate only the suffix
        3. Terminate early when cost exceeds current best

        This gives ~2x speedup from skipping prefix recomputation,
        plus additional savings from early termination.
        """
        m = len(seq)
        txn_to_insert = txn_data[txn_idx]
        txn_ins_len = txn_to_insert[0][3]

        best_cost = cost_bound
        best_pos = 0

        # Maintain prefix state incrementally
        prefix_ks = {}
        prefix_tc = 0

        for p in range(m + 1):
            # Copy prefix state for suffix evaluation
            ks = {k: [v[0], v[1]] for k, v in prefix_ks.items()}
            tc = prefix_tc

            # Process inserted transaction
            txn_start = 1
            for (op_type, key, pos, _) in txn_to_insert:
                if key in ks:
                    state = ks[key]
                    if op_type == 'w':
                        key_start = state[1] + 1
                    else:
                        key_start = state[0] + 1 if state[0] > 0 else 0
                    constraint = key_start - pos + 1
                    if constraint > txn_start:
                        txn_start = constraint
            txn_end = txn_start + txn_ins_len - 1
            cost = txn_end - tc
            if cost < 0:
                cost = 0
            tc += cost

            # Early check: if inserting alone already exceeds best, skip suffix
            if tc >= best_cost:
                # Advance prefix
                if p < m:
                    txn = txn_data[seq[p]]
                    txn_len = txn[0][3]
                    txn_start_p = 1
                    for (op_type, key, pos, _) in txn:
                        if key in prefix_ks:
                            state = prefix_ks[key]
                            if op_type == 'w':
                                key_start = state[1] + 1
                            else:
                                key_start = state[0] + 1 if state[0] > 0 else 0
                            constraint = key_start - pos + 1
                            if constraint > txn_start_p:
                                txn_start_p = constraint
                    txn_end_p = txn_start_p + txn_len - 1
                    cost_p = txn_end_p - prefix_tc
                    if cost_p < 0:
                        cost_p = 0
                    prefix_tc += cost_p
                    for (op_type, key, pos, _) in txn:
                        key_time = txn_start_p + pos - 1
                        if key in prefix_ks:
                            state = prefix_ks[key]
                            if op_type == 'w':
                                if key_time > state[0]:
                                    state[0] = key_time
                            if key_time > state[1]:
                                state[1] = key_time
                        else:
                            if op_type == 'w':
                                prefix_ks[key] = [key_time, key_time]
                            else:
                                prefix_ks[key] = [0, key_time]
                continue

            # Update key_state for inserted transaction
            for (op_type, key, pos, _) in txn_to_insert:
                key_time = txn_start + pos - 1
                if key in ks:
                    state = ks[key]
                    if op_type == 'w':
                        if key_time > state[0]:
                            state[0] = key_time
                    if key_time > state[1]:
                        state[1] = key_time
                else:
                    if op_type == 'w':
                        ks[key] = [key_time, key_time]
                    else:
                        ks[key] = [0, key_time]

            # Process suffix seq[p..m-1] with early termination
            terminated_early = False
            for i in range(p, m):
                txn = txn_data[seq[i]]
                txn_len = txn[0][3]
                txn_start_s = 1
                for (op_type, key, pos, _) in txn:
                    if key in ks:
                        state = ks[key]
                        if op_type == 'w':
                            key_start = state[1] + 1
                        else:
                            key_start = state[0] + 1 if state[0] > 0 else 0
                        constraint = key_start - pos + 1
                        if constraint > txn_start_s:
                            txn_start_s = constraint
                txn_end_s = txn_start_s + txn_len - 1
                cost_s = txn_end_s - tc
                if cost_s < 0:
                    cost_s = 0
                tc += cost_s
                if tc >= best_cost:
                    terminated_early = True
                    break
                # Update key_state for suffix txn
                for (op_type, key, pos, _) in txn:
                    key_time = txn_start_s + pos - 1
                    if key in ks:
                        state = ks[key]
                        if op_type == 'w':
                            if key_time > state[0]:
                                state[0] = key_time
                        if key_time > state[1]:
                            state[1] = key_time
                    else:
                        if op_type == 'w':
                            ks[key] = [key_time, key_time]
                        else:
                            ks[key] = [0, key_time]

            if not terminated_early and tc < best_cost:
                best_cost = tc
                best_pos = p

            # Advance prefix: process seq[p]
            if p < m:
                txn = txn_data[seq[p]]
                txn_len = txn[0][3]
                txn_start_p = 1
                for (op_type, key, pos, _) in txn:
                    if key in prefix_ks:
                        state = prefix_ks[key]
                        if op_type == 'w':
                            key_start = state[1] + 1
                        else:
                            key_start = state[0] + 1 if state[0] > 0 else 0
                        constraint = key_start - pos + 1
                        if constraint > txn_start_p:
                            txn_start_p = constraint
                txn_end_p = txn_start_p + txn_len - 1
                cost_p = txn_end_p - prefix_tc
                if cost_p < 0:
                    cost_p = 0
                prefix_tc += cost_p
                for (op_type, key, pos, _) in txn:
                    key_time = txn_start_p + pos - 1
                    if key in prefix_ks:
                        state = prefix_ks[key]
                        if op_type == 'w':
                            if key_time > state[0]:
                                state[0] = key_time
                        if key_time > state[1]:
                            state[1] = key_time
                    else:
                        if op_type == 'w':
                            prefix_ks[key] = [key_time, key_time]
                        else:
                            prefix_ks[key] = [0, key_time]

        return best_pos, best_cost

    def neh_construction(txn_order=None, sample_positions=None):
        """NEH-style construction using fast prefix-sweep insertion."""
        if txn_order is None:
            txn_order = list(range(n))
            random.shuffle(txn_order)

        seq = [txn_order[0]]
        for i in range(1, n):
            if elapsed() > time_budget * 0.95:
                seq.append(txn_order[i])
                continue
            txn = txn_order[i]
            m = len(seq)
            if sample_positions and m > sample_positions:
                # For large sequences during NEH, sample positions
                positions = random.sample(range(m + 1), min(sample_positions, m + 1))
                best_cost = float('inf')
                best_pos = 0
                for pos in positions:
                    candidate = seq[:pos] + [txn] + seq[pos:]
                    cost = fast_eval(candidate)
                    if cost < best_cost:
                        best_cost = cost
                        best_pos = pos
                seq.insert(best_pos, txn)
            else:
                # Use fast prefix-sweep insertion
                best_pos, _ = fast_find_best_insert(seq, txn)
                seq.insert(best_pos, txn)
        return fast_eval(seq), seq

    def neh_with_priority():
        """NEH with conflict-based priority (heaviest first)."""
        conflict_counts = []
        for i in range(n):
            txn_ops = workload.txns[i]
            writes = sum(1 for op in txn_ops if op[0] == 'w')
            total_ops = len(txn_ops)
            conflict_counts.append((writes * 2 + total_ops, i))
        conflict_counts.sort(reverse=True)
        txn_order = [t[1] for t in conflict_counts]
        return neh_construction(txn_order, sample_positions=50)

    def full_relocate_pass(seq, cost):
        """Move each transaction to its best position (one pass)."""
        current_seq = list(seq)
        current_cost = cost
        improved = False
        for i in range(n):
            if elapsed() > time_budget * 0.93:
                break
            txn = current_seq[i]
            new_seq = current_seq[:i] + current_seq[i+1:]
            best_pos, best_cost = fast_find_best_insert(new_seq, txn, current_cost)
            if best_cost < current_cost:
                new_seq.insert(best_pos, txn)
                current_seq = new_seq
                current_cost = best_cost
                improved = True
        return current_cost, current_seq, improved

    def bottleneck_relocate(seq, cost, num_targets=8):
        """Relocate highest-delay transactions to best positions."""
        _, delays = fast_eval_with_delays(seq)
        current_seq = list(seq)
        current_cost = cost
        improved = False

        targets = sorted(range(n), key=lambda i: delays[i], reverse=True)
        for pos_idx in targets[:num_targets]:
            if elapsed() > time_budget * 0.93:
                break
            txn = current_seq[pos_idx]
            new_seq = current_seq[:pos_idx] + current_seq[pos_idx+1:]
            best_pos, best_cost = fast_find_best_insert(new_seq, txn, current_cost)
            if best_cost < current_cost:
                new_seq.insert(best_pos, txn)
                current_seq = new_seq
                current_cost = best_cost
                improved = True
                _, delays = fast_eval_with_delays(current_seq)
                targets = sorted(range(n), key=lambda i: delays[i], reverse=True)

        return current_cost, current_seq, improved

    def iterated_greedy(init_seq, init_cost, ig_time_frac, d=3):
        """IG with destroy/reconstruct and SA acceptance."""
        best = list(init_seq)
        best_cost = init_cost
        current = list(init_seq)
        current_cost = init_cost

        ig_start = time.time()
        ig_budget = (time_budget - elapsed()) * ig_time_frac

        T_start = best_cost * 0.04
        T_end = 0.01

        iteration = 0
        bottleneck_interval = 30

        while True:
            ig_elapsed = time.time() - ig_start
            if ig_elapsed >= ig_budget or elapsed() > time_budget * 0.93:
                break

            progress = ig_elapsed / ig_budget
            T = T_start * ((T_end / T_start) ** progress)

            # Periodic bottleneck targeting
            if iteration > 0 and iteration % bottleneck_interval == 0:
                bn_cost, bn_seq, bn_improved = bottleneck_relocate(
                    current, current_cost, num_targets=5
                )
                if bn_improved:
                    current = bn_seq
                    current_cost = bn_cost
                    if current_cost < best_cost:
                        best_cost = current_cost
                        best = list(current)
                    iteration += 1
                    continue

            # Destruction: remove d random transactions
            candidate = list(current)
            indices = sorted(random.sample(range(n), d), reverse=True)
            removed = []
            for idx in indices:
                removed.append(candidate.pop(idx))
            random.shuffle(removed)

            # Reconstruction: greedy reinsertion using fast prefix-sweep
            for txn in removed:
                best_pos, _ = fast_find_best_insert(candidate, txn)
                candidate.insert(best_pos, txn)

            new_cost = fast_eval(candidate)

            # Acceptance
            delta = new_cost - current_cost
            if delta < 0:
                current = candidate
                current_cost = new_cost
                if current_cost < best_cost:
                    best_cost = current_cost
                    best = list(current)
            elif T > 0 and random.random() < math.exp(-delta / max(T, 0.001)):
                current = candidate
                current_cost = new_cost

            # Restart from best if diverged too much
            if random.random() < 0.01 and current_cost > best_cost * 1.15:
                current = list(best)
                current_cost = best_cost

            iteration += 1

        return best_cost, best

    # === Main algorithm ===

    # Phase 1: NEH Construction
    best_cost = float('inf')
    best_schedule = None

    cost, sched = neh_with_priority()
    if cost < best_cost:
        best_cost = cost
        best_schedule = sched

    # Random NEH constructions
    construction_deadline = time_budget * 0.12
    while elapsed() < construction_deadline:
        cost, sched = neh_construction(sample_positions=50)
        if cost < best_cost:
            best_cost = cost
            best_schedule = sched

    # Phase 2: Full relocate pass (intensive local search)
    if elapsed() < time_budget * 0.80:
        new_cost, new_sched, _ = full_relocate_pass(best_schedule, best_cost)
        if new_cost < best_cost:
            best_cost = new_cost
            best_schedule = new_sched

    # Phase 3: IG with d=3 (60% of remaining time)
    if elapsed() < time_budget * 0.85:
        ig_cost, ig_sched = iterated_greedy(best_schedule, best_cost, 0.6, d=3)
        if ig_cost < best_cost:
            best_cost = ig_cost
            best_schedule = ig_sched

    # Phase 4: IG with d=2 (remaining time, finer grained)
    if elapsed() < time_budget * 0.85:
        ig_cost2, ig_sched2 = iterated_greedy(best_schedule, best_cost, 0.9, d=2)
        if ig_cost2 < best_cost:
            best_cost = ig_cost2
            best_schedule = ig_sched2

    # Verify with official evaluator
    official_cost = workload.get_opt_seq_cost(best_schedule)
    return official_cost, best_schedule

# EVOLVE-BLOCK-END

def get_random_costs():
    workload_size = 100
    workload = Workload(WORKLOAD_1)

    makespan1, schedule1 = get_best_schedule(workload, 10)
    cost1 = workload.get_opt_seq_cost(schedule1)

    workload2 = Workload(WORKLOAD_2)
    makespan2, schedule2 = get_best_schedule(workload2, 10)
    cost2 = workload2.get_opt_seq_cost(schedule2)

    workload3 = Workload(WORKLOAD_3)
    makespan3, schedule3 = get_best_schedule(workload3, 10)
    cost3 = workload3.get_opt_seq_cost(schedule3)
    print(cost1, cost2, cost3)
    return cost1 + cost2 + cost3, [schedule1, schedule2, schedule3]


if __name__ == "__main__":
    makespan, schedule = get_random_costs()
    print(f"Makespan: {makespan}")

