p_tc = 0

for p in range(m + 1):
    # Copy prefix state (fast array copy)
    kw = p_kw[:]
    ka = p_ka[:]
    tc = p_tc

    # Process inserted transaction
    txn_start = 1
    for (is_write, key_idx, pos, _) in txn_to_insert:
        ka_val = ka[key_idx]
        if ca_val := ka_val:
            if is_write:
                key_start = ca_val + 1
            else:
                kw_val = kw[key_idx]
                key_start = kw_val + 1 if kw_val > 0 else 0
            constraint = key_start - pos + 1
            if constraint > txn_start:
                txn_start = constraint
    txn_end = txn_start + txn_ins_len - 1
    cost = txn_end - tc
    if cost < 0:
        cost = 0
    tc += cost

    # Early skip if already exceeds best
    if tc >= best_cost:
        # Advance prefix
        if p < m:
            txn_p = txn_data[seq[p]]
            txn_len_p = txn_lens[seq[p]]
            ts = 1
            for (is_write, key_idx, pos, _) in txn_p:
                ka_val = p_ka[key_idx]
                if ka_val:
                    if is_write:
                        ks = ka_val + 1
                    else:
                        kw_val = p_kw[key_idx]
                        ks = kw_val + 1 if kw_val > 0 else 0
                    c = ks - pos + 1
                    if c > ts:
                        ts = c
            te = ts + txn_len_p - 1
            cp = te - p_tc
            if cp < 0:
                cp = 0
            p_tc += cp

